using System.Collections;using System.Collections.Generic;using UnityEngine;public class CameraMovement : MonoBehaviour{    [SerializeField] float rotateSpeed;    // [SerializeField] Slider mouseSlider;    [SerializeField] Transform player;    float xRotation = 0f;    GameObject indicator;    Key currentKey;    // Start is called once before the first execution of Update after the MonoBehaviour is created    void Start()    {        GameObject canvas = GameObject.Find("Canvas");        indicator = canvas.transform.Find("PlayerUI/Indicator").gameObject;        Cursor.lockState = CursorLockMode.Locked;        //LoadMouseSensitivity();    }    // Update is called once per frame    void Update()    {        if (Time.timeScale == 0) return;        if (PlayerController.isCinemaMode) return;        float mouseX = Input.GetAxis("Mouse X") * rotateSpeed;        float mouseY = Input.GetAxis("Mouse Y") * rotateSpeed;        xRotation -= mouseY;        xRotation = Mathf.Clamp(xRotation, -90f, 90f);        transform.localRotation = Quaternion.Euler(xRotation, 0f, 0f);        player.Rotate(Vector3.up * mouseX);        if (Physics.Raycast(transform.position, transform.TransformDirection(Vector3.forward), out RaycastHit hit, 2.5f)) // plr position, ray direction, output, length        {            Key key = hit.collider.gameObject.GetComponent<Key>();            if (key != null && key.isGrabbable == false)            {                indicator.SetActive(true);                key.isGrabbable = true;                currentKey = key;            }            else if (key == null && currentKey != null && indicator.activeSelf)            {                indicator.SetActive(false);                currentKey.isGrabbable = false;                currentKey = null;            }        }        // needs to disable indicator and isgrabbable    }    // public void SetMouseSensitivity()    // {    //     rotateSpeed = mouseSlider.value;    //     PlayerPrefs.SetFloat("MouseSensitivity", rotateSpeed);    // }       // void LoadMouseSensitivity()    // {    //     if (PlayerPrefs.HasKey("MouseSensitivity"))    //     {    //         mouseSlider.value = PlayerPrefs.GetFloat("MouseSensitivity");    //     }    //     SetMouseSensitivity();    // }}